import json
import logging
from kafka import KafkaConsumer, TopicPartition

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

class FinancialTransactionConsumer:
    def __init__(self, bootstrap_servers, group_id, topics,
                 value_deserializer=lambda m: json.loads(m.decode('utf-8'))):
        """
        Initializes the Kafka consumer.
        :param bootstrap_servers: List of Kafka bootstrap servers.
        :param group_id: Consumer group ID.
        :param topics: List of topics to subscribe to.
        :param value_deserializer: Function to deserialize message values.
        """
        self.bootstrap_servers = bootstrap_servers
        self.group_id = group_id
        self.topics = topics
        self.value_deserializer = value_deserializer
        self.consumer = None
        self.message_handlers = {}
        self._initialize_consumer()

    def _initialize_consumer(self):
        """Initializes the KafkaConsumer instance."""
        try:
            self.consumer = KafkaConsumer(
                *self.topics,
                bootstrap_servers=self.bootstrap_servers,
                group_id=self.group_id,
                value_deserializer=self.value_deserializer,
                auto_offset_reset='earliest',  # Start reading from the earliest available offset
                enable_auto_commit=True,       # Automatically commit offsets
                auto_commit_interval_ms=5000,  # Commit every 5 seconds
                consumer_timeout_ms=1000       # Poll timeout
            )
            logging.info(f"Kafka consumer initialized for topics: {self.topics}, group_id: {self.group_id}")
        except Exception as e:
            logging.error(f"Failed to initialize Kafka consumer: {e}")
            raise

    def register_handler(self, transaction_type, handler_func):
        """
        Registers a message handler for a specific transaction type.
        :param transaction_type: The 'type' field in the transaction message to handle.
        :param handler_func: The function to call when a message of this type is received.
                             It should accept one argument: the deserialized message.
        """
        if not callable(handler_func):
            raise ValueError("Handler function must be callable.")
        self.message_handlers[transaction_type] = handler_func
        logging.info(f"Registered handler for transaction type: '{transaction_type}'")

    def _process_message(self, message):
        """
        Processes a single Kafka message. Deserializes it and dispatches to
        the appropriate handler based on the 'type' field.
        """
        try:
            transaction_data = message.value
            if not isinstance(transaction_data, dict):
                logging.warning(f"Skipping non-dictionary message: {transaction_data}")
                return

            transaction_type = transaction_data.get('type')
            if not transaction_type:
                logging.warning(f"Message missing 'type' field: {transaction_data}")
                return

            handler = self.message_handlers.get(transaction_type)
            if handler:
                logging.info(f"Processing transaction type '{transaction_type}' from topic '{message.topic}' partition {message.partition} offset {message.offset}")
                handler(transaction_data)
                # You might add custom metrics or logging here for successful processing
            else:
                logging.warning(f"No handler registered for transaction type: '{transaction_type}'. Message: {transaction_data}")

        except json.JSONDecodeError as e:
            logging.error(f"Error decoding JSON message from topic {message.topic} partition {message.partition} offset {message.offset}: {e}. Raw message: {message.value}")
        except Exception as e:
            logging.error(f"Error processing message from topic {message.topic} partition {message.partition} offset {message.offset}: {e}. Message: {message.value}", exc_info=True)

    def start_consuming(self):
        """Starts consuming messages from Kafka topics."""
        if not self.consumer:
            logging.error("Consumer not initialized. Cannot start consuming.")
            return

        logging.info("Starting Kafka consumer...")
        try:
            for message in self.consumer:
                self._process_message(message)
        except KeyboardInterrupt:
            logging.info("Consumer stopped by user.")
        except Exception as e:
            logging.error(f"An unexpected error occurred during consumption: {e}", exc_info=True)
        finally:
            self.consumer.close()
            logging.info("Kafka consumer closed.")

    def stop_consuming(self):
        """Stops the Kafka consumer."""
        if self.consumer:
            self.consumer.close()
            logging.info("Kafka consumer explicitly stopped and closed.")


